// Extract data from webhook
const webhookData = $input.first().json.body;
const formType = webhookData.formType;
const data = webhookData.data;
const metadata = webhookData.metadata;

// Extract name parts
const nameParts = data.name ? data.name.split(' ') : ['', ''];
const firstName = nameParts[0] || '';
const lastName = nameParts.slice(1).join(' ') || '';

// Extract domain from email
const email = data.email || '';
const domain = email.split('@')[1] || '';

// Map team size to employee count
const teamSizeMap = {
  '1-10': 10,
  '11-50': 50,
  '51-200': 200,
  '201-500': 500,
  '501-1000': 1000,
  '1000+': 1000
};
const employees = teamSizeMap[data.teamSize] || null;

// Build note content
let noteBody = '';
let noteTitle = '';

if (formType === 'consultation') {
  noteTitle = `Consultation Request - ${data.company || 'Unknown Company'}`;
  noteBody = `## Consultation Request

**Name:** ${data.name}
**Email:** ${data.email}
**Company:** ${data.company}
**Role:** ${data.role}
**Team Size:** ${data.teamSize}

### Technical Requirements
**Tech Stack:** ${JSON.stringify(data.techStack || {})}
**Security Level:** ${data.securityLevel}
**Compliance:** ${JSON.stringify(data.compliance || [])}

### Message
${data.message || 'No message provided'}

---
**Submitted:** ${metadata?.submittedAt || new Date().toISOString()}
**Source:** ${metadata?.source || 'website'}`;
} else {
  noteTitle = `Contact Form - ${data.subject || 'No Subject'}`;
  noteBody = `## Contact Form Submission

**From:** ${data.name} <${data.email}>
**Subject:** ${data.subject}

### Message
${data.message}

---
**Submitted:** ${metadata?.submittedAt || new Date().toISOString()}
**Source:** ${metadata?.source || 'website'}`;
}

return [{
  json: {
    formType,
    firstName,
    lastName,
    email,
    domain,
    companyName: data.company || '',
    jobTitle: data.role || '',
    employees,
    noteTitle,
    noteBody,
    originalData: data
  }
}];
